using System;\nusing System.Net.WebSockets;\nusing System.Text;\nusing System.Text.Json;\nusing System.Threading;\nusing System.Threading.Tasks;\nusing Xunit;\nusing Microsoft.Extensions.Logging;\nusing PitWall.WebSocket;\nusing PitWall.Models;\nusing Moq;\n\nnamespace PitWall.Tests.Integration.WebSocket\n{\n    /// <summary>\n    /// Integration tests for WebSocket server with actual client connections.\n    /// Tests real-world telemetry streaming scenarios and multi-client broadcast.\n    /// </summary>\n    public class WebSocketServerIntegrationTests : IAsyncLifetime\n    {\n        private WebSocketServer _server;\n        private Mock<ILogger<WebSocketServer>> _mockLogger;\n        private CancellationTokenSource _testCancellation;\n        private const int TestPort = 9995;\n        private const string LocalhostUri = \"ws://localhost:9995\";\n\n        public async Task InitializeAsync()\n        {\n            _mockLogger = new Mock<ILogger<WebSocketServer>>();\n            _testCancellation = new CancellationTokenSource();\n            _server = new WebSocketServer(_mockLogger.Object, TestPort);\n            await _server.StartAsync(_testCancellation.Token);\n            await Task.Delay(200); // Allow server to fully initialize\n        }\n\n        public async Task DisposeAsync()\n        {\n            _testCancellation.Cancel();\n            await _server.StopAsync(CancellationToken.None);\n            _server?.Dispose();\n            _testCancellation?.Dispose();\n        }\n\n        [Fact(Skip = \"Requires WebSocket listener to be available\")] // Skip in CI without WebSocket support\n        public async Task SingleClient_ConnectsAndReceivesTelemetry_Successfully()\n        {\n            // Arrange\n            var clientWebSocket = new ClientWebSocket();\n            var snapshot = CreateTestTelemetrySnapshot();\n            var receivedMessage = string.Empty;\n\n            try\n            {\n                // Act - Connect client\n                await clientWebSocket.ConnectAsync(\n                    new Uri(LocalhostUri),\n                    CancellationToken.None);\n\n                Assert.Equal(WebSocketState.Open, clientWebSocket.State);\n\n                // Act - Send telemetry\n                await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n\n                // Act - Try to receive\n                var buffer = new byte[4096];\n                var cts = new CancellationTokenSource(TimeSpan.FromSeconds(2));\n                var result = await clientWebSocket.ReceiveAsync(\n                    new ArraySegment<byte>(buffer),\n                    cts.Token);\n\n                if (result.Count > 0)\n                {\n                    receivedMessage = Encoding.UTF8.GetString(buffer, 0, result.Count);\n                }\n\n                // Assert\n                Assert.NotEmpty(receivedMessage);\n            }\n            finally\n            {\n                await clientWebSocket.CloseAsync(\n                    WebSocketCloseStatus.NormalClosure,\n                    \"Test complete\",\n                    CancellationToken.None);\n                clientWebSocket.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_HighFrequency_CompletesSuccessfully()\n        {\n            // Arrange\n            var snapshots = new TelemetrySnapshot[100];\n            for (int i = 0; i < 100; i++)\n            {\n                snapshots[i] = CreateTestTelemetrySnapshot();\n            }\n\n            var sw = System.Diagnostics.Stopwatch.StartNew();\n\n            // Act\n            foreach (var snapshot in snapshots)\n            {\n                await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n            }\n\n            sw.Stop();\n\n            // Assert\n            Assert.True(sw.ElapsedMilliseconds < 5000, \"100 broadcasts should complete in <5 seconds\");\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_WithLargePayload_CompletesSuccessfully()\n        {\n            // Arrange\n            var snapshot = CreateTestTelemetrySnapshot();\n\n            // Act - Send large payload\n            await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n\n            // Assert - No exception thrown\n            Assert.True(true);\n        }\n\n        [Fact]\n        public async Task ServerStatistics_AfterBroadcast_UpdatesCorrectly()\n        {\n            // Arrange\n            var snapshot = CreateTestTelemetrySnapshot();\n            var initialStats = _server.GetServerStatistics();\n\n            // Act\n            await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n            await Task.Delay(100);\n\n            var finalStats = _server.GetServerStatistics();\n\n            // Assert\n            Assert.NotNull(finalStats);\n            // Stats should be available even if no clients connected\n        }\n\n        [Fact]\n        public async Task ConcurrentBroadcasts_MultipleSnapshots_AllComplete()\n        {\n            // Arrange\n            var tasks = new Task[10];\n            for (int i = 0; i < 10; i++)\n            {\n                tasks[i] = _server.BroadcastTelemetryAsync(\n                    CreateTestTelemetrySnapshot(),\n                    CancellationToken.None);\n            }\n\n            // Act & Assert\n            await Task.WhenAll(tasks);\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_RealWorldQualifyingScenario_CompletesSuccessfully()\n        {\n            // Simulate a qualifying lap with speed progression\n            var laps = CreateQualifyingLapTelemetry();\n\n            // Act\n            foreach (var snapshot in laps)\n            {\n                await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n                // Slight delay to simulate real-time\n                await Task.Delay(10);\n            }\n\n            // Assert\n            Assert.Equal(50, laps.Count); // 50 data points in qualifying lap\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_RealWorldPitStopScenario_CompletesSuccessfully()\n        {\n            // Simulate pit stop sequence\n            var pitStopData = CreatePitStopTelemetry();\n\n            // Act\n            foreach (var snapshot in pitStopData)\n            {\n                await _server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n                await Task.Delay(5); // Faster timing for pit stop\n            }\n\n            // Assert\n            Assert.Equal(60, pitStopData.Count); // 60 data points in pit stop\n        }\n\n        [Fact]\n        public async Task ConnectionStatistics_WhenRequested_ReturnsValidData()\n        {\n            // Act\n            var initialStats = _server.GetConnectionStatistics();\n\n            await _server.BroadcastTelemetryAsync(\n                CreateTestTelemetrySnapshot(),\n                CancellationToken.None);\n\n            var statsAfterBroadcast = _server.GetConnectionStatistics();\n\n            // Assert\n            Assert.NotNull(initialStats);\n            Assert.NotNull(statsAfterBroadcast);\n        }\n\n        [Fact]\n        public async Task BroadcastTelemetry_WithCancellationToken_RespectsCancellation()\n        {\n            // Arrange\n            var snapshot = CreateTestTelemetrySnapshot();\n            var cts = new CancellationTokenSource();\n\n            // Act & Assert\n            try\n            {\n                cts.CancelAfter(TimeSpan.FromMilliseconds(100));\n                await _server.BroadcastTelemetryAsync(snapshot, cts.Token);\n            }\n            catch (OperationCanceledException)\n            {\n                // Expected in some cases\n            }\n        }\n\n        private static TelemetrySnapshot CreateTestTelemetrySnapshot()\n        {\n            return new TelemetrySnapshot\n            {\n                Timestamp = DateTime.UtcNow,\n                SessionId = Guid.NewGuid().ToString(),\n                VehicleData = new VehicleData\n                {\n                    Speed = 150.5f,\n                    Throttle = 0.85f,\n                    Brake = 0.0f,\n                    Clutch = 0.0f,\n                    Gear = 4,\n                    EngineRpm = 7500,\n                    FuelRemaining = 45.5f,\n                    SteeringAngle = 0.15f,\n                    InvalidFlagBits = 0\n                },\n                TireData = new TireInfo[4]\n                {\n                    new TireInfo { Temperature = 95.5f, Pressure_Kpa = 220.0f, Wear = 0.15f },\n                    new TireInfo { Temperature = 94.2f, Pressure_Kpa = 218.0f, Wear = 0.14f },\n                    new TireInfo { Temperature = 92.8f, Pressure_Kpa = 215.0f, Wear = 0.16f },\n                    new TireInfo { Temperature = 93.5f, Pressure_Kpa = 217.0f, Wear = 0.15f }\n                },\n                PerformanceData = new PerformanceData\n                {\n                    LateralAccelerationG = 1.2f,\n                    LongitudinalAccelerationG = 0.8f,\n                    VerticalAccelerationG = 0.1f,\n                    LapNumber = 5,\n                    LapTime_Seconds = 95.234f\n                },\n                EnvironmentData = new EnvironmentData\n                {\n                    AirTemperature = 22.5f,\n                    RoadTemperature = 25.0f,\n                    RollAngle = 0.05f,\n                    PitchAngle = -0.02f,\n                    YawAngle = 0.15f\n                }\n            };\n        }\n\n        private static List<TelemetrySnapshot> CreateQualifyingLapTelemetry()\n        {\n            var snapshots = new List<TelemetrySnapshot>();\n            // Simulate 50 telemetry points of qualifying lap\n            for (int i = 0; i < 50; i++)\n            {\n                var progress = i / 50.0f;\n                var snapshot = CreateTestTelemetrySnapshot();\n                snapshot.VehicleData!.Speed = 100 + (progress * 200); // 0-200 km/h progression\n                snapshot.VehicleData.EngineRpm = 3000 + (progress * 8000); // RPM progression\n                snapshots.Add(snapshot);\n            }\n            return snapshots;\n        }\n\n        private static List<TelemetrySnapshot> CreatePitStopTelemetry()\n        {\n            var snapshots = new List<TelemetrySnapshot>();\n            // Simulate 60 telemetry points of pit stop sequence\n            for (int i = 0; i < 60; i++)\n            {\n                var snapshot = CreateTestTelemetrySnapshot();\n                \n                if (i < 15)\n                    snapshot.VehicleData!.Speed = 320 - (i * 10); // Braking to pit\n                else if (i < 40)\n                    snapshot.VehicleData!.Speed = 40; // In pit lane\n                else\n                    snapshot.VehicleData!.Speed = 40 + ((i - 40) * 5); // Exiting pit lane\n\n                snapshots.Add(snapshot);\n            }\n            return snapshots;\n        }\n    }\n}\n